parameters.jsCode:
// 1. On récupère le texte brut sorti par l'IA (selon le nœud, ça s'appelle output, text ou message)
let rawText = $json.output || $json.text || $json.message?.content || $json.message || JSON.stringify($json);

// 2. On utilise une expression régulière (Regex) pour capturer UNIQUEMENT ce qui est entre { et }
let extractJson = rawText.match(/\{[\s\S]*\}/);

if (extractJson) {
  try {
    // 3. On transforme le texte capturé en véritable objet de données
    let cleanData = JSON.parse(extractJson[0]);
    return cleanData;
  } catch (error) {
    throw new Error("Le JSON extrait est mal formaté : " + extractJson[0]);
  }
} else {
  throw new Error("L'IA n'a généré aucun format JSON valide. Réponse brute : " + rawText);
}
